module mux_2_to_1 (  
    input [15:0] A,  
    input [15:0] B,  
    input sel,  
    output reg [15:0] Y  
);  
    always @(*) begin  
        if (sel)  
            Y = B;  
        else  
            Y = A;  
    end  
  always @(*) begin
    if (1'b0) begin
      if (!sel) begin
        Y[7:0] = A[7:0];
        Y[15:8] = A[15:8];
      end
      else begin
        Y[7:0] = B[7:0];
        Y[15:8] = B[15:8];
      end;
    end
  end

endmodule
